import { Button } from '@material-ui/core'
import axios from 'axios'
import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'

export default function Register() {
    const navigate = useNavigate();
    const [input, setInput] = useState({
        name: '',
        studentID: '',
        password: ''
    })

    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;

        setInput(input => ({...input, [name]: value}));
    }

    const handleSubmit = (event) => {
        event.preventDefault();
        const sendInput = {
            name:input.name,
            studentID:input.studentID,
            password:input.password
        }

        axios.post('http://localhost:80/api/register.php', sendInput)
        .then((result) => {
            if(result.input.Status == 'Invalid') {
                alert('Invalid User');
            } else {
                navigate('/')
            }
        })
    }

  return (
    <div>
        
        <center>
        <h1>Register</h1>
        <form onSubmit={handleSubmit}>

            <label>Name: </label>
            <input type="text" name='name' value={input.name} onChange={handleChange} />
            <br /><br />

            <label>Student ID: </label>
            <input type="text" name='studentID' value={input.studentID} onChange={handleChange} />
            <br /><br />

            <label>Password: </label>
            <input type="password" name='password' value={input.password} onChange={handleChange} />
            <br /><br />

            <Button type='submit' name='submit' variant='contained' color='secondary' >Register</Button>

        </form>
        </center>
    </div>
  )
}
